  ".obsidian/themes/pochade-notebook/theme.css": "@import url('https://fonts.googleapis.com/css2?family=Poly:ital@0;1&display=swap');\n\n\n\n\n\n:root {\n\n  --bg-color: #FDF8E7;\n\n  --fg-color: #2d3a2d;\n\n\n\n  --neutral-background-color:#f0eee4;\n\n  --highlight-color: #8C001A;\n\n  --neutral-color: #FEF6F3;\n\n  --color-border: var(--neutral-color);\n\n  --font-family: \"Poly\", serif;\n\n\n\n  /* SVG pattern fills */\n\n  --pattern-fill: var(--bg-color);\n\n  --pattern-stroke: var(--fg-color);\n\n\n\n  /* SVG data elements (bars, circles, paths, slices) */\n\n  --data-element-stroke: var(--fg-color);\n\n  --data-element-stroke-width: 1;\n\n\n\n  /* SVG axes */\n\n  --axis-stroke: #999;\n\n  --axis-stroke-width: 1;\n\n\n\n  /* SVG labels */\n\n  --label-fill: var(--fg-color);\n\n  --label-font-size: 10px;\n\n  --label-font-family:  \"Poly\", serif;\n\n\n\n\n\n  --color-base-00: var(--bg-color) !important;\n\n    --color-base-05: #fcfcfc;\n\n    --color-base-10: #fafafa;\n\n    --color-base-20: #f6f6f6;\n\n    --color-base-25: #e3e3e3;\n\n    --color-base-30: #e0e0e0;\n\n    --color-base-35: #d4d4d4;\n\n    --color-base-40: #bdbdbd;\n\n    --color-base-50: #ababab;\n\n    --color-base-60: #707070;\n\n    --color-base-70: #5c5c5c;\n\n    --color-base-100: #222222;\n\n\n\n}\n\n\n\n\n\n*,\n\n*::before,\n\n*::after {\n\n  box-sizing: border-box;\n\n  margin: 0;\n\n  padding: 0;\n\n}\n\n\n\nbody {\n\n  font-family: var(--font-family);\n\n  line-height: 1.6;\n\n  color: var(--fg-color);\n\n  background-color: var(--bg-color);\n\n \n\n}\n\n\n\na {\n\n  color: var(--highlight-color);\n\n}\n\n\n\nheader {\n\n  border-bottom: 1px solid #ddd;\n\n  padding: 1rem 0;\n\n  margin-bottom: 2rem;\n\n}\n\n\n\nheader nav {\n\n  display: flex;\n\n  justify-content: space-between;\n\n  align-items: center;\n\n  flex-wrap: wrap;\n\n  gap: 0.5rem;\n\n}\n\n\n\n.site-title {\n\n  font-size: 1.25rem;\n\n  font-weight: 700;\n\n  color: var(--fg-color);\n\n  text-decoration: none;\n\n}\n\n\n\n.nav-links {\n\n  display: flex;\n\n  gap: 1.25rem;\n\n}\n\n\n\n.nav-links a {\n\n  color: var(--fg-color);\n\n  text-decoration: none;\n\n  font-size: 0.9rem;\n\n}\n\n\n\n.nav-links a:hover {\n\n  color: var(--highlight-color);\n\n}\n\n\n\nmain {\n\n  min-height: 60vh;\n\n  padding-bottom: 2rem;\n\n}\n\n\n\nh1, h2, h3, h4 {\n\n  margin-top: 1.5em;\n\n  margin-bottom: 0.5em;\n\n  line-height: 1.3;\n\n}\n\n\n\nh1 { font-size: 2rem; }\n\nh2 { font-size: 1.5rem; }\n\nh3 { font-size: 1.2rem; }\n\n\n\np {\n\n  margin-bottom: 1em;\n\n}\n\n\n\narticle {\n\n  padding-bottom: 2rem;\n\n}\n\n\n\n.post-meta {\n\n  color: var(--neutral);\n\n  font-size: 0.9rem;\n\n  margin-bottom: 1.5rem;\n\n}\n\n\n\n.post-meta time {\n\n  font-style: italic;\n\n}\n\n\n\nsvg {\n\n  max-width: 100%;\n\n  height: auto;\n\n  display: block;\n\n  margin: 1.5rem auto;\n\n  background: var(--bg-color);\n\n}\n\n\n\n.data-element {\n\n  stroke: var(--data-element-stroke);\n\n  stroke-width: var(--data-element-stroke-width);\n\n}\n\n\n\n.axis {\n\n  stroke: var(--axis-stroke);\n\n  stroke-width: var(--axis-stroke-width);\n\n}\n\n\n\n.label {\n\n  fill: var(--label-fill);\n\n  font-size: var(--label-font-size);\n\n  font-family: var(--label-font-family);\n\n  font-weight: 400;\n\n}\n\n\n\n.chart-error {\n\n  border: 2px solid #d00;\n\n  padding: 10px;\n\n  margin: 10px 0;\n\n  background: #fee;\n\n}\n\n\n\npre.code {\n\n  background: var(--neutral-background-color);\n\n  border: 1px solid rgba(0,0,0,0.1);\n\n  border-radius: 4px;\n\n  padding: 1rem;\n\n  overflow-x: auto;\n\n  font-size: 0.85rem;\n\n  margin: 1rem 0;\n\n}\n\n\n\ncode {\n\n  font-family: monospace;\n\n  font-size: 0.85em;\n\n  background: var(--neutral-background-color);\n\n  padding: 0.15em 0.3em;\n\n  border-radius: 3px;\n\n}\n\n\n\npre.code code {\n\n  background: none;\n\n  padding: 0;\n\n}\n\n\n\n.keyword { color: #7928a1; font-weight: 600; }\n\n.string  { color: #067d17; }\n\n.comment { color: #888; font-style: italic; }\n\n.literal { color: #0055aa; }\n\n\n\nul, ol {\n\n  margin: 0.5em 0 1em 1.5em;\n\n}\n\n\n\nli {\n\n  margin-bottom: 0.3em;\n\n}\n\n\n\n.post-list {\n\n  list-style: none;\n\n  margin-left: 0;\n\n  padding: 0;\n\n}\n\n\n\n.post-list li {\n\n  border-bottom: 1px solid #eee;\n\n  padding: 1rem 0;\n\n}\n\n\n\n.post-list li:last-child {\n\n  border-bottom: none;\n\n}\n\n\n\n.post-list h3 {\n\n  margin-top: 0;\n\n  margin-bottom: 0.25em;\n\n}\n\n\n\n.post-list p {\n\n  color: #555;\n\n  font-size: 0.9rem;\n\n  margin-bottom: 0.25em;\n\n}\n\n\n\n.post-list small {\n\n  color: #999;\n\n  font-size: 0.8rem;\n\n}\n\n\n\n.tags-list {\n\n  list-style: none;\n\n  margin-left: 0;\n\n  padding: 0;\n\n  display: flex;\n\n  flex-wrap: wrap;\n\n  gap: 0.5rem;\n\n}\n\n\n\n.tags-list li a {\n\n  display: inline-block;\n\n  background: var(--neutral-color);\n\n  padding: 0.3rem 0.75rem;\n\n  border-radius: 3px;\n\n  text-decoration: none;\n\n  color: var(--highlight-color);\n\n  font-size: 0.9rem;\n\n}\n\n\n\n.tags-list li a:hover {\n\n  background: #ddd;\n\n}\n\n\n\n.pagination {\n\n  display: flex;\n\n  justify-content: center;\n\n  align-items: center;\n\n  gap: 1.5rem;\n\n  margin: 2rem 0;\n\n  padding-top: 1rem;\n\n  border-top: 1px solid #eee;\n\n}\n\n\n\n.pagination span {\n\n  color: #999;\n\n  font-size: 0.9rem;\n\n}\n\n\n\n.site-description {\n\n  color: #666;\n\n  font-size: 1rem;\n\n  margin-bottom: 2rem;\n\n}\n\n\n\n#search-input,\n\n#tag-search {\n\n  width: 100%;\n\n  padding: 0.75rem;\n\n  font-size: 1rem;\n\n  border: 1px solid #ccc;\n\n  border-radius: 4px;\n\n  margin-bottom: 1rem;\n\n}\n\n\n\n#search-input:focus,\n\n#tag-search:focus {\n\n  outline: none;\n\n  border-color: #0055aa;\n\n  box-shadow: 0 0 0 2px rgba(0, 85, 170, 0.15);\n\n}\n\n\n\n.search-results {\n\n  list-style: none;\n\n  margin-left: 0;\n\n  padding: 0;\n\n}\n\n\n\n.search-results li {\n\n  border-bottom: 1px solid #eee;\n\n  padding: 0.75rem 0;\n\n}\n\n\n\ntable {\n\n  border-collapse: collapse;\n\n  width: 100%;\n\n  margin: 1rem 0;\n\n}\n\n\n\nth, td {\n\n  border: 1px solid #ddd;\n\n  padding: 0.5rem 0.75rem;\n\n  text-align: left;\n\n}\n\n\n\nth {\n\n  background: var(--bg-color);\n\n  font-weight: 600;\n\n}\n\n\n\nblockquote {\n\n  border-left: 3px solid #ccc;\n\n  margin: 1rem 0;\n\n  padding: 0.5rem 1rem;\n\n  color: #555;\n\n}\n\n\n\nabbr {\n\n  text-decoration: underline dotted;\n\n  cursor: help;\n\n}\n\n\n\nfigure.chart-figure {\n\n  margin: 1.5rem 0;\n\n}\n\n\n\n.chart-figcaption {\n\n  padding: 0.75rem;\n\n  border-top: none;\n\n  font-size: 0.85rem;\n\n  text-align: center;\n\n}\n\n\n\n.chart-figcaption table {\n\n  margin: 0;\n\n  font-size: 0.9rem;\n\n}\n\n\n\n.chart-figcaption td:first-child {\n\n  width: 30%;\n\n}\n\n\n\nfooter {\n\n  border-top: 1px solid #ddd;\n\n  padding: 1rem 0;\n\n  margin-top: 2rem;\n\n  color: var(--fg-color);\n\n  font-size: 0.85rem;\n\n  text-align: center;\n\n}\n\n\n\n@view-transition {\n\n  navigation: auto;\n\n}\n\n\n\n::view-transition-old(root),\n\n::view-transition-new(root) {\n\n  animation-duration: 0.3s;\n\n}\n\n\n\n::view-transition-old(root) {\n\n  animation-name: fade-out;\n\n}\n\n\n\n::view-transition-new(root) {\n\n  animation-name: fade-in;\n\n}\n\n\n\n@keyframes fade-out {\n\n  to {\n\n    opacity: 0;\n\n  }\n\n}\n\n\n\n@keyframes fade-in {\n\n  from {\n\n    opacity: 0;\n\n  }\n\n}",
